import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Prism","description":"","frontmatter":{},"headers":[],"relativePath":"ecosystem/prism.md","filePath":"ecosystem/prism.md"}'),i={name:"ecosystem/prism.md"};function o(n,e,c,l,d,h){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="prism" tabindex="-1">Prism <a class="header-anchor" href="#prism" aria-label="Permalink to &quot;Prism&quot;">​</a></h1><p>Prism is the visualization platform. It renders UEF traces as interactive step-by-step playbacks and architecture graphs as navigable topology views.</p><h2 id="surfaces" tabindex="-1">Surfaces <a class="header-anchor" href="#surfaces" aria-label="Permalink to &quot;Surfaces&quot;">​</a></h2><ul><li><strong>Runtime Studio</strong> — UEF trace playback with code viewer, stack/heap panels</li><li><strong>Architecture Lens</strong> — UGF topology with service graph and dependency view</li></ul><h2 id="lenses" tabindex="-1">Lenses <a class="header-anchor" href="#lenses" aria-label="Permalink to &quot;Lenses&quot;">​</a></h2><ul><li><strong>Debug Truth</strong> — raw state, precise frames, exact references</li><li><strong>Learning Lens</strong> — same data, calmer explanation</li></ul><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Prism has a working UI with two surfaces and two lenses. Wiring to Nerva for real trace data is in progress.</p><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td>Framework</td><td>React 18</td></tr><tr><td>Language</td><td>TypeScript</td></tr><tr><td>Build</td><td>Vite</td></tr></tbody></table>',10)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
